
'use client';

import React, { createContext, useContext, useState, useEffect, useRef } from 'react';
import { calculateRoutes, RouteData, RouteStep } from '@/services/navigation/routeService';

interface TelemetryPoint {
  time: number;
  speed: number;
  distance: number;
}

export type RunMode = 'free' | '0-60' | '0-100' | '100-200' | '1/4mile';

export interface SearchResult {
  name: string;
  lat: number;
  lng: number;
  displayName: string;
}

export interface RunSummaryData {
  id: string;
  runType: string;
  time: number;
  peakSpeed: number;
  avgSpeed: number;
  distance: number;
  points: [number, number][];
  city: string;
  createdAt: string;
}

interface DrivingContextType {
  speed: number;
  isDriving: boolean;
  peakSpeed: number;
  tripTime: number;
  tripDistance: number;
  hasGps: boolean;
  currentCoords: { lat: number; lng: number } | null;
  heading: number | null;
  routePoints: [number, number][];
  telemetry: TelemetryPoint[];
  startTime: Date | null;
  runMode: RunMode;
  dragTime: number | null;
  isDragFinished: boolean;
  isDragActive: boolean;
  isWakeLockActive: boolean;
  countdown: number;
  isJumpStart: boolean;
  lastRunSummary: RunSummaryData | null;
  // Navigation State
  destination: SearchResult | null;
  routeData: RouteData | null;
  availableRoutes: RouteData[];
  isNavigating: boolean;
  currentStep: RouteStep | null;
  currentRoadName: string;
  distanceToNextStep: number;
  remainingDistance: number;
  remainingDuration: number;
  dynamicZoom: number;
  setDestination: (dest: SearchResult | null) => void;
  setRouteData: (data: RouteData | null) => void;
  setAvailableRoutes: (routes: RouteData[]) => void;
  setIsNavigating: (nav: boolean) => void;
  clearNavigation: () => void;
  setDynamicZoom: (zoom: number) => void;
  // Controls
  setRunMode: (mode: RunMode) => void;
  startTrip: () => void;
  startDragCountdown: () => void;
  stopTrip: () => void;
  resetTrip: () => void;
  requestWakeLock: () => Promise<void>;
  setLastRunSummary: (summary: RunSummaryData | null) => void;
}

const DrivingContext = createContext<DrivingContextType | undefined>(undefined);

export function DrivingProvider({ children }: { children: React.ReactNode }) {
  const isDrivingRef = useRef(false);
  const totalDistanceRef = useRef(0);
  const peakSpeedRef = useRef(0);
  const lastPosRef = useRef<{ lat: number; lng: number; timestamp: number } | null>(null);
  const wakeLockRef = useRef<any>(null);
  const lastRerouteTimeRef = useRef<number>(0);
  const headingBufferRef = useRef<number[]>([]);
  const tripStartTimeRef = useRef<number | null>(null);

  const isDragFinishedRef = useRef(false);
  const isDragActiveRef = useRef(false);
  const dragTimerRef = useRef<number | null>(null);
  const dragStartDistRef = useRef<number>(0);
  const countdownRef = useRef(0);

  const [speed, setSpeed] = useState(0);
  const [isDriving, setIsDriving] = useState(false);
  const [peakSpeed, setPeakSpeed] = useState(0);
  const [tripTime, setTripTime] = useState(0);
  const [tripDistance, setTripDistance] = useState(0);
  const [hasGps, setHasGps] = useState(true);
  const [currentCoords, setCurrentCoords] = useState<{ lat: number; lng: number } | null>(null);
  const [heading, setHeading] = useState<number | null>(null);
  const [routePoints, setRoutePoints] = useState<[number, number][]>([]);
  const [telemetry, setTelemetry] = useState<TelemetryPoint[]>([]);
  const [startTime, setStartTime] = useState<Date | null>(null);
  const [runMode, setRunMode] = useState<RunMode>('free');
  const [dragTime, setDragTime] = useState<number | null>(null);
  const [isDragFinished, setIsDragFinished] = useState(false);
  const [isDragActive, setIsDragActive] = useState(false);
  const [isWakeLockActive, setIsWakeLockActive] = useState(false);
  const [countdown, setCountdown] = useState(0);
  const [isJumpStart, setIsJumpStart] = useState(false);
  const [lastRunSummary, setLastRunSummary] = useState<RunSummaryData | null>(null);

  const countdownIntervalRef = useRef<NodeJS.Timeout | null>(null);

  const [destination, setDestination] = useState<SearchResult | null>(null);
  const [routeData, setRouteData] = useState<RouteData | null>(null);
  const [availableRoutes, setAvailableRoutes] = useState<RouteData[]>([]);
  const [isNavigating, setIsNavigating] = useState(false);
  const [currentStep, setCurrentStep] = useState<RouteStep | null>(null);
  const [currentRoadName, setCurrentRoadName] = useState("");
  const [distanceToNextStep, setDistanceToNextStep] = useState(0);
  const [remainingDistance, setRemainingDistance] = useState(0);
  const [remainingDuration, setRemainingDuration] = useState(0);
  const [dynamicZoom, setDynamicZoom] = useState(17);
  const [userZoomOverride, setUserZoomOverride] = useState<number | null>(null);

  const REROUTE_DISTANCE_THRESHOLD = 80;

  const requestWakeLock = async () => {
    if (typeof window !== 'undefined' && 'wakeLock' in navigator) {
      try {
        // @ts-ignore
        wakeLockRef.current = await navigator.wakeLock.request('screen');
        setIsWakeLockActive(true);
        
        // Listener for release
        wakeLockRef.current.addEventListener('release', () => {
          setIsWakeLockActive(false);
        });
      } catch (err: any) {
        setIsWakeLockActive(false);
      }
    }
  };

  const releaseWakeLock = async () => {
    if (wakeLockRef.current) {
      try {
        await wakeLockRef.current.release();
        wakeLockRef.current = null;
        setIsWakeLockActive(false);
      } catch (err) {}
    }
  };

  // Visibility change listener to re-request wake lock
  useEffect(() => {
    const handleVisibilityChange = async () => {
      if (document.visibilityState === 'visible' && (isDrivingRef.current || isNavigating)) {
        await requestWakeLock();
      }
    };
    document.addEventListener('visibilitychange', handleVisibilityChange);
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange);
  }, [isNavigating]);

  const getSmoothedHeading = (newHeading: number | null) => {
    if (newHeading === null || isNaN(newHeading)) return heading;
    headingBufferRef.current.push(newHeading);
    if (headingBufferRef.current.length > 5) headingBufferRef.current.shift();
    const sinSum = headingBufferRef.current.reduce((acc, val) => acc + Math.sin(val * Math.PI / 180), 0);
    const cosSum = headingBufferRef.current.reduce((acc, val) => acc + Math.cos(val * Math.PI / 180), 0);
    const avgRad = Math.atan2(sinSum, cosSum);
    return (avgRad * 180 / Math.PI + 360) % 360;
  };

  const calculateDist = (lat1: number, lon1: number, lat2: number, lon2: number) => {
    const R = 6371e3;
    const phi1 = (lat1 * Math.PI) / 180;
    const phi2 = (lat2 * Math.PI) / 180;
    const dPhi = ((lat2 - lat1) * Math.PI) / 180;
    const dLon = ((lon2 - lon1) * Math.PI) / 180;
    const a = Math.sin(dPhi / 2) * Math.sin(dPhi / 2) + Math.cos(phi1) * Math.cos(phi2) * Math.sin(dLon / 2) * Math.sin(dLon / 2);
    return R * (2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a)));
  };

  const handleDragLogic = (kmh: number, currentDist: number) => {
    const now = performance.now();
    if (!isDragActiveRef.current && !isDragFinishedRef.current) {
      if (countdownRef.current > 0 && countdownRef.current < 5 && kmh > 1) {
        setIsJumpStart(true);
      }
      if (kmh > 0.5 && countdownRef.current === 5) {
        isDragActiveRef.current = true;
        setIsDragActive(true);
        dragTimerRef.current = now;
        dragStartDistRef.current = currentDist;
      }
    } else if (isDragActiveRef.current) {
      let finished = false;
      if (runMode === '0-60' && kmh >= 60) finished = true;
      else if (runMode === '0-100' && kmh >= 100) finished = true;
      else if (runMode === '100-200' && kmh >= 200) finished = true;
      else if (runMode === '1/4mile' && (currentDist - dragStartDistRef.current) >= 402.3) finished = true;

      if (finished) {
        const finalTime = (now - dragTimerRef.current!) / 1000;
        setDragTime(finalTime);
        setIsDragFinished(true);
        isDragFinishedRef.current = true;
        setIsDragActive(false);
        isDragActiveRef.current = false;
        const avgSpeed = (currentDist - dragStartDistRef.current) / finalTime * 3.6;
        setLastRunSummary({
          id: Math.random().toString(36).substring(7),
          runType: runMode === '1/4mile' ? '1/4 Mile' : runMode,
          time: finalTime,
          peakSpeed: peakSpeedRef.current,
          avgSpeed: Math.round(avgSpeed),
          distance: Math.round(currentDist - dragStartDistRef.current),
          points: [...routePoints] as [number, number][],
          city: "Kosovë",
          createdAt: new Date().toISOString()
        });
      } else {
        setDragTime((now - dragTimerRef.current!) / 1000);
      }
    }
  };

  useEffect(() => {
    let watchId: number;
    if (typeof navigator !== 'undefined' && navigator.geolocation) {
      watchId = navigator.geolocation.watchPosition(
        (position) => {
          setHasGps(true);
          const { latitude, longitude, speed: mps, heading: rawHeading } = position.coords;
          const kmh = mps !== null && mps >= 0.5 ? Math.round(mps * 3.6) : 0;
          if (isDrivingRef.current && runMode !== 'free' && !isDragFinishedRef.current) handleDragLogic(kmh, totalDistanceRef.current);
          setSpeed(kmh);
          setCurrentCoords({ lat: latitude, lng: longitude });
          let finalHeading = rawHeading;
          if ((finalHeading === null || isNaN(finalHeading!)) && lastPosRef.current && kmh > 1) {
            const dy = latitude - lastPosRef.current.lat;
            const dx = Math.cos(latitude * Math.PI / 180) * (longitude - lastPosRef.current.lng);
            finalHeading = (Math.atan2(dx, dy) * 180 / Math.PI + 360) % 360;
          }
          if (finalHeading !== null && !isNaN(finalHeading!)) setHeading(getSmoothedHeading(finalHeading));
          if (isDrivingRef.current) {
            setRoutePoints(prev => {
              const lastPoint = prev[prev.length - 1];
              if (lastPoint && calculateDist(lastPoint[0], lastPoint[1], latitude, longitude) < 1.5) return prev;
              return [...prev, [latitude, longitude]];
            });
            if (tripStartTimeRef.current) {
              const currentTime = (Date.now() - tripStartTimeRef.current) / 1000;
              setTelemetry(prev => [...prev, { time: currentTime, speed: kmh, distance: totalDistanceRef.current }]);
              setTripTime(currentTime);
            }
            if (lastPosRef.current) {
              const moved = calculateDist(lastPosRef.current.lat, lastPosRef.current.lng, latitude, longitude);
              if (moved > 0.3) {
                totalDistanceRef.current += moved;
                setTripDistance(totalDistanceRef.current);
              }
            }
            if (kmh > peakSpeedRef.current) {
              peakSpeedRef.current = kmh;
              setPeakSpeed(kmh);
            }
          }
          lastPosRef.current = { lat: latitude, lng: longitude, timestamp: position.timestamp };
        },
        () => setHasGps(false),
        { enableHighAccuracy: true, maximumAge: 0, timeout: 5000 }
      );
    }
    return () => { if (watchId) navigator.geolocation.clearWatch(watchId); };
  }, [runMode]); 

  useEffect(() => {
    if (isNavigating && currentCoords && routeData && destination) {
      const steps = routeData.steps;
      let targetStep = null;
      for (let i = 0; i < steps.length; i++) {
        const d = calculateDist(currentCoords.lat, currentCoords.lng, steps[i].location[0], steps[i].location[1]);
        if (d > 20) {
          setDistanceToNextStep(Math.round(d));
          targetStep = steps[i];
          break;
        }
      }
      if (targetStep) setCurrentStep(targetStep);
      const coords = routeData.coordinates;
      let closestIdx = -1, minCoordDist = 1000;
      for (let i = 0; i < coords.length; i++) {
        const d = calculateDist(currentCoords.lat, currentCoords.lng, coords[i][0], coords[i][1]);
        if (d < minCoordDist) { minCoordDist = d; closestIdx = i; }
      }
      if (closestIdx !== -1) {
        const remainingCoords = coords.slice(closestIdx);
        let remainingD = 0;
        if (remainingCoords.length > 1) {
          for (let i = 0; i < remainingCoords.length - 1; i++) {
            remainingD += calculateDist(remainingCoords[i][0], remainingCoords[i][1], remainingCoords[i+1][0], remainingCoords[i+1][1]);
          }
        }
        setRemainingDistance(remainingD);
        setRemainingDuration(routeData.duration * (remainingD / (routeData.distance || 1)));
        setCurrentRoadName(routeData.steps[0]?.name || routeData.summary || "Rrugë e Kosovës");
      }
      if (userZoomOverride === null) {
        let targetZoom = 17;
        if (distanceToNextStep < 100) targetZoom = 19;
        else if (distanceToNextStep < 300) targetZoom = 18;
        else if (speed > 80) targetZoom = 14;
        else if (speed > 50) targetZoom = 16;
        if (Math.abs(dynamicZoom - targetZoom) > 0.5) setDynamicZoom(targetZoom);
      } else setDynamicZoom(userZoomOverride);

      if (minCoordDist > REROUTE_DISTANCE_THRESHOLD) {
        const now = Date.now();
        if (now - lastRerouteTimeRef.current > 8000) {
          lastRerouteTimeRef.current = now;
          calculateRoutes(currentCoords, { lat: destination.lat, lng: destination.lng }).then(routes => {
            if (routes && routes.length > 0) { setAvailableRoutes(routes); setRouteData(routes[0]); }
          }).catch(() => {});
        }
      }
    }
  }, [currentCoords?.lat, currentCoords?.lng, isNavigating, destination?.lat, destination?.lng, speed, routeData?.distance, distanceToNextStep, userZoomOverride]);

  const startTrip = () => {
    setIsDriving(true);
    isDrivingRef.current = true;
    setIsJumpStart(false);
    const now = new Date();
    setStartTime(now);
    tripStartTimeRef.current = now.getTime();
    setRoutePoints([]);
    setTelemetry([]);
    setIsDragFinished(false);
    isDragFinishedRef.current = false;
    setIsDragActive(false);
    isDragActiveRef.current = false;
    setDragTime(0);
    setLastRunSummary(null);
    requestWakeLock();
  };

  const startDragCountdown = () => {
    setLastRunSummary(null);
    setIsJumpStart(false);
    setIsDragFinished(false);
    isDragFinishedRef.current = false;
    setDragTime(0);
    setCountdown(0);
    countdownRef.current = 0;
    requestWakeLock();
    if (countdownIntervalRef.current) clearInterval(countdownIntervalRef.current);
    countdownIntervalRef.current = setInterval(() => {
      setCountdown(prev => {
        const next = prev + 1;
        countdownRef.current = next;
        if (next === 5) {
          if (countdownIntervalRef.current) clearInterval(countdownIntervalRef.current);
          setIsDriving(true);
          isDrivingRef.current = true;
          tripStartTimeRef.current = Date.now();
        }
        return next;
      });
    }, 1000);
  };

  const stopTrip = () => {
    if (isDrivingRef.current) {
      const duration = tripStartTimeRef.current ? (Date.now() - tripStartTimeRef.current) / 1000 : 0;
      const avgSpeed = duration > 0 ? (totalDistanceRef.current / duration) * 3.6 : 0;
      setLastRunSummary({
        id: Math.random().toString(36).substring(7),
        runType: runMode === 'free' ? 'Top Speed' : (runMode === '1/4mile' ? '1/4 Mile' : runMode),
        time: runMode === 'free' ? duration : (dragTime || 0),
        peakSpeed: peakSpeedRef.current,
        avgSpeed: Math.round(avgSpeed),
        distance: Math.round(totalDistanceRef.current),
        points: [...routePoints] as [number, number][],
        city: "Kosovë",
        createdAt: new Date().toISOString()
      });
    }
    setIsDriving(false);
    isDrivingRef.current = false;
    tripStartTimeRef.current = null;
    setIsDragActive(false);
    isDragActiveRef.current = false;
    if (countdownIntervalRef.current) {
      clearInterval(countdownIntervalRef.current);
      countdownIntervalRef.current = null;
    }
    setCountdown(0);
    countdownRef.current = 0;
    releaseWakeLock();
  };

  const resetTrip = () => {
    setTripTime(0); setTripDistance(0); setPeakSpeed(0);
    totalDistanceRef.current = 0; peakSpeedRef.current = 0;
    setRoutePoints([]); setTelemetry([]); setDragTime(0);
    setIsDragFinished(false); isDragFinishedRef.current = false;
    setIsDragActive(false); isDragActiveRef.current = false;
    setCountdown(0); countdownRef.current = 0;
    setIsJumpStart(false); setLastRunSummary(null);
    if (countdownIntervalRef.current) {
      clearInterval(countdownIntervalRef.current);
      countdownIntervalRef.current = null;
    }
    releaseWakeLock();
  };

  const clearNavigation = () => {
    setDestination(null); setRouteData(null); setAvailableRoutes([]);
    setIsNavigating(false); setCurrentStep(null); setCurrentRoadName("");
    setDistanceToNextStep(0); setRemainingDistance(0); setRemainingDuration(0); setUserZoomOverride(null);
    if (!isDrivingRef.current) releaseWakeLock();
  };

  return (
    <DrivingContext.Provider value={{
      speed, isDriving, peakSpeed, tripTime, tripDistance, hasGps,
      currentCoords, heading, routePoints, telemetry, startTime,
      runMode, dragTime, isDragFinished, isDragActive, isWakeLockActive, countdown, isJumpStart,
      lastRunSummary,
      destination, routeData, availableRoutes, isNavigating,
      currentStep, currentRoadName, distanceToNextStep, remainingDistance, remainingDuration, dynamicZoom,
      setDestination, setRouteData, setAvailableRoutes, setIsNavigating, clearNavigation,
      setDynamicZoom: setUserZoomOverride,
      setRunMode, startTrip, startDragCountdown, stopTrip, resetTrip, requestWakeLock, setLastRunSummary
    }}>
      {children}
    </DrivingContext.Provider>
  );
}

export const useDriving = () => {
  const context = useContext(DrivingContext);
  if (!context) throw new Error('useDriving must be used within a DrivingProvider');
  return context;
};
